  bgMid: "#0A1228",
  bgTo: "#0D1B3E",
  card: "rgba(13, 21, 44, 0.62)",
  cardBorder: "rgba(122, 152, 255, 0.14)",
  inset: "rgba(8, 13, 30, 0.55)",
  text: "#E8EDF9",
  dim: "#8B97B8",
  faint: "#5A688F",
  accentFrom: "#4F6BF0",
