const Glass = ({ children, style, className = "" }) => (
  <div
    className={className}
    style={{
      background: T.card,
      border: `1px solid ${T.cardBorder}`,
      borderRadius: 20,
      backdropFilter: "blur(18px)",
      WebkitBackdropFilter: "blur(18px)",
      boxShadow: "0 24px 60px -24px rgba(0,0,0,0.6), inset 0 1px 0 rgba(255,255,255,0.04)",
      ...style,
    }}
  >
    {children}
  </div>
);

const ScoreRing = ({ label, score, color, delay = 0 }) => {
  const [val, setVal] = useState(0);
  useEffect(() => {
    const t = setTimeout(() => setVal(score), 250 + delay);
    return () => clearTimeout(t);
  }, [score, delay]);
  const r = 52, c = 2 * Math.PI * r;
  return (
    <div className="flex flex-col items-center" style={{ minWidth: 140 }}>
      <div style={{ position: "relative", width: 128, height: 128 }}>
        <svg width="128" height="128" viewBox="0 0 128 128">
          <circle cx="64" cy="64" r={r} fill="none" stroke="rgba(122,152,255,0.12)" strokeWidth="9" />
          <circle
            cx="64" cy="64" r={r} fill="none"
            stroke={color} strokeWidth="9" strokeLinecap="round"
            strokeDasharray={c}
            strokeDashoffset={c - (c * val) / 100}
            transform="rotate(-90 64 64)"
            style={{ transition: "stroke-dashoffset 1.1s cubic-bezier(.22,1,.36,1)" }}
          />
        </svg>
        <div
          style={{
            position: "absolute", inset: 0, display: "flex", flexDirection: "column",
            alignItems: "center", justifyContent: "center",
          }}
        >
          <span style={{ fontFamily: serif, fontSize: 30, fontWeight: 700, color: T.text, lineHeight: 1 }}>
            {score}
          </span>
          <span style={{ fontSize: 11, color: T.dim, marginTop: 2 }}>/ 100</span>
        </div>
      </div>
      <span style={{ marginTop: 10, fontSize: 13, letterSpacing: "0.06em", textTransform: "uppercase", color: T.dim, fontWeight: 600 }}>
        {label}
      </span>
    </div>
  );
};

const Bar = ({ pct, color }) => {
  const [w, setW] = useState(0);
  useEffect(() => {
    const t = setTimeout(() => setW(pct), 300);
    return () => clearTimeout(t);
  }, [pct]);
  return (
    <div style={{ height: 6, borderRadius: 999, background: "rgba(122,152,255,0.12)", overflow: "hidden" }}>
      <div style={{ height: "100%", width: `${w}%`, borderRadius: 999, background: color, transition: "width 1s cubic-bezier(.22,1,.36,1)" }} />
    </div>
  );
};

